const xml = $input.first().json.data || '';
const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;
const SERVICE_KEYWORDS = {
  'WooCommerce & E-commerce Dev': ['woocommerce', 'ecommerce', 'e-commerce', 'shopify', 'online store'],
  'AI Automation & Workflow Integration': ['automation', 'n8n', 'zapier', 'make.com', 'workflow', 'ai agent', 'chatbot'],
  'UI/UX Design (Figma)': ['figma', 'ui/ux', 'ui design', 'ux design', 'wireframe', 'prototype'],
  'SEO & Performance Optimization': ['seo', 'search engine', 'google ranking', 'performance', 'page speed'],
  'Custom Web App Development': ['web app', 'web application', 'saas', 'dashboard', 'portal', 'custom software'],
  'WordPress Dev': ['wordpress', 'wp', 'elementor', 'divi', 'cms']
};

while ((match = itemRegex.exec(xml)) !== null) {
  const item = match[1];
  const get = (tag) => {
    const r = new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>|<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`);
    const m = item.match(r);
    return m ? (m[1] || m[2] || '').trim() : '';
  };
  const title = get('title');
  const link = get('link');
  const rawDesc = get('description').replace(/<[^>]+>/g, '');
  const description = rawDesc.substring(0, 600);
  const pubDate = get('pubDate');
  const budgetMatch = rawDesc.match(/Budget:\s*\$([\d,]+)/i);
  const budget = budgetMatch ? '$' + budgetMatch[1] : 'Not specified';

  const combined = (title + ' ' + description).toLowerCase();
  let matched_service = null;
  let best_count = 0;
  for (const [service, keywords] of Object.entries(SERVICE_KEYWORDS)) {
    const count = keywords.filter(k => combined.includes(k)).length;
    if (count > best_count) { best_count = count; matched_service = service; }
  }
  if (!matched_service) continue;

  const budget_num = parseInt((budgetMatch ? budgetMatch[1] : '0').replace(/,/g, '')) || 0;
  let priority = 'Low';
  if (best_count >= 3 || budget_num >= 500) priority = 'High';
  else if (best_count >= 2 || budget_num >= 200) priority = 'Medium';

  items.push({
    platform: 'Upwork',
    title: title.substring(0, 120),
    link,
    description,
    budget,
    matched_service,
    priority,
    pub_date: pubDate,
    contact: 'Via Upwork Proposal',
    status: 'Pending'
  });
}
return items.length > 0 ? items.map(i => ({ json: i })) : [{ json: { __empty: true, platform: 'Upwork' } }];

const html = $input.first().json.data || '';
const items = [];

// Extract gig data from Fiverr's JSON embedded in the page
const jsonMatch = html.match(/window\.__RELAY_STORE__\s*=\s*(\{[\s\S]*?\});/);
if (jsonMatch) {
  try {
    const store = JSON.parse(jsonMatch[1]);
    const keys = Object.keys(store).filter(k => store[k] && store[k].title && store[k].sellerName);
    for (const key of keys.slice(0, 20)) {
      const gig = store[key];
      const title = gig.title || '';
      const seller = gig.sellerName || '';
      const price = gig.price ? '$' + gig.price : 'See Fiverr';
      const gigUrl = gig.url ? 'https://www.fiverr.com' + gig.url : '';
      const desc = (gig.packageIncludes || gig.description || '').substring(0, 400);

      const combined = title.toLowerCase();
      const keywords = ['wordpress', 'woocommerce', 'web app', 'automation', 'figma', 'seo', 'ecommerce', 'website', 'ui ux'];
      const matched = keywords.filter(k => combined.includes(k));
      if (matched.length === 0) continue;

      let matched_service = 'Web Development';
      if (combined.includes('woocommerce') || combined.includes('ecommerce')) matched_service = 'WooCommerce & E-commerce Dev';
      else if (combined.includes('automation')) matched_service = 'AI Automation & Workflow Integration';
      else if (combined.includes('figma') || combined.includes('ui')) matched_service = 'UI/UX Design (Figma)';
      else if (combined.includes('seo')) matched_service = 'SEO & Performance Optimization';
      else if (combined.includes('wordpress')) matched_service = 'WordPress Dev';

      items.push({
        platform: 'Fiverr',
        title,
        link: gigUrl,
        description: `Seller: ${seller}. ${desc}`,
        budget: price,
        matched_service,
        priority: matched.length >= 2 ? 'Medium' : 'Low',
        pub_date: new Date().toISOString(),
        contact: `Fiverr seller: ${seller}`,
        status: 'Pending'
      });
    }
  } catch(e) {}
}

// Fallback: regex extraction if JSON not found
if (items.length === 0) {
  const gigRegex = /data-gig-id="(\d+)"[\s\S]*?class="gig-title"[^>]*>([^<]+)</g;
  let m;
  while ((m = gigRegex.exec(html)) !== null) {
    items.push({
      platform: 'Fiverr',
      title: m[2].trim(),
      link: 'https://www.fiverr.com',
      description: 'See Fiverr for full details',
      budget: 'See Fiverr',
      matched_service: 'Web Development',
      priority: 'Low',
      pub_date: new Date().toISOString(),
      contact: 'Via Fiverr',
      status: 'Pending'
    });
  }
}

return items.length > 0 ? items.map(i => ({ json: i })) : [{ json: { __empty: true, platform: 'Fiverr' } }];

const places = $input.first().json;
const results = Array.isArray(places) ? places : (places.items || []);
const items = [];

for (const place of results) {
  const name = place.title || place.name || '';
  const address = place.address || place.street || '';
  const phone = place.phone || place.phoneUnformatted || '';
  const website = place.website || '';
  const rating = parseFloat(place.totalScore || place.rating || 0);
  const reviews = parseInt(place.reviewsCount || place.user_ratings_total || 0);
  const category = (place.categoryName || place.types || ['business'])[0] || 'business';
  const url = place.url || place.website || `https://maps.google.com/?q=${encodeURIComponent(name)}`;

  if (!name) continue;

  // Target: no website, or low rating/reviews = needs digital help
  const needs_website = !website || website === '';
  const weak_presence = rating < 3.8 || reviews < 15;
  if (!needs_website && !weak_presence) continue;

  const priority = needs_website ? 'High' : (rating < 3.5 ? 'High' : 'Medium');
  const reason = needs_website ? 'No website found' : `Low rating (${rating}) or few reviews (${reviews})`;

  items.push({
    platform: 'Google Maps',
    title: `${name} — ${reason}`,
    link: url,
    description: `Business: ${name}. Category: ${category}. Address: ${address}. Rating: ${rating}/5 (${reviews} reviews). ${needs_website ? 'No website listed on Google Maps.' : 'Weak online presence.'}`,
    budget: 'To be discussed',
    matched_service: 'WordPress Website Design & Dev',
    priority,
    pub_date: new Date().toISOString(),
    contact: phone || 'Find via Google Maps',
    status: 'Pending',
    business_name: name,
    business_phone: phone,
    business_address: address
  });
}

return items.length > 0 ? items.map(i => ({ json: i })) : [{ json: { __empty: true, platform: 'Google Maps' } }];

const allLeads = $('Merge All Leads').all().map(i => i.json).filter(l => !l.__empty);
const existing = $('Read Existing Leads').all().map(i => i.json);
const seenLinks = new Set(existing.map(l => (l.Link || l.link || '').trim()).filter(Boolean));
const seenTitles = new Set(existing.map(l => (l.Title || l.title || '').toLowerCase().trim()).filter(Boolean));

const fresh = allLeads.filter(lead => {
  if (!lead.title || !lead.platform) return false;
  const link = (lead.link || '').trim();
  const title = (lead.title || '').toLowerCase().trim();
  if (link && seenLinks.has(link)) return false;
  if (title && seenTitles.has(title)) return false;
  return true;
});

if (fresh.length === 0) {
  return [{ json: { __no_new_leads: true, message: 'No new leads this run. All leads already in sheet.' } }];
}

return fresh.map(l => ({ json: l }));

