const lead = $('New Leads Found?').first().json;
const geminiResp = $input.first().json;

let subject = 'WebCorps Can Help With Your Project';
let body = `Hi,\n\nWe came across your project and believe WebCorps can help. We specialize in ${lead.matched_service} and have delivered similar work for clients before.\n\nWould you be open to a quick call this week?\n\nWebCorps Team | webcorps.com`;

try {
  const raw = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const clean = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(clean);
  if (parsed.subject) subject = parsed.subject;
  if (parsed.body) body = parsed.body;
} catch(e) {}

return [{ json: {
  ...lead,
  email_subject: subject,
  email_body: body,
  lead_id: 'WC-' + Date.now()
}}];
